#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
    int val;
    struct Node *next;
} Node;

// Structure to represent stack
typedef struct {
    Node *head; // Top of Stack
    int size; // Size
} LinkedListStack;

// Function to create a new node
Node* createNode(int d) {
    Node *element = (Node*) malloc(sizeof(Node));
    element->val = d;
    element->next = NULL;
    return element;
}

// Function to create a new stack
LinkedListStack* createStack() {
    LinkedListStack *stack = (LinkedListStack*) malloc(sizeof(LinkedListStack));
    stack->head = NULL;
    stack->size = 0;
    return stack;
}

// Method to push an element onto the stack
void push(LinkedListStack *stack, int x) {
    Node *element = createNode(x);
    element->next = stack->head;
    stack->head = element;
    stack->size++;
}

// Method to pop an element from the stack
int pop(LinkedListStack *stack) {
    if (stack->head == NULL) {
        return -1;
    }
    int value = stack->head->val;
    Node *temp = stack->head;
    stack->head = stack->head->next;
    free(temp);
    stack->size--;
    return value;
}

// Method to get the top element of the stack
int top(LinkedListStack *stack) {
    if (stack->head == NULL) {
        return -1;
    }
    return stack->head->val;
}

// Method to check if the stack is empty
int isEmpty(LinkedListStack *stack) {
    return stack->size == 0;
}

